{
  "top_k_industries": {
    "value": 8,
    "desc": "盘前选出的强势行业数量（Top K）。越小越集中，越大越分散。建议 3~10。"
  },
  "top_n": {
    "value": 8,
    "desc": "最终输出榜单的股票数量（Top N）。如果你希望每个行业只选一只，一般设置为等于 top_k_industries。"
  },
  "exclude_st": {
    "value": true,
    "desc": "是否过滤 ST 股票。"
  },
  "min_turnover_cny": {
    "value": 30000000.0,
    "desc": "成交额过滤阈值（元）。低于该成交额的股票不纳入候选。"
  },
  "lookback_days": {
    "value": 60,
    "desc": "特征计算用的回看窗口（交易日）。影响趋势/波动等特征。"
  },
  "train_years": {
    "value": 3,
    "desc": "训练样本回看年数（用于概率模型训练）。"
  },
  "target_return_3": {
    "value": 0.03,
    "desc": "3日目标收益阈值（用于训练标签）。例如 0.03 表示 3日涨幅>=3% 视为命中。"
  },
  "target_return_5": {
    "value": 0.05,
    "desc": "5日目标收益阈值（用于训练标签）。例如 0.05 表示 5日涨幅>=5% 视为命中。"
  },
  "cash_score_base": {
    "value": 0.55,
    "desc": "现金门槛基础值（0~1）。越高越保守。"
  },
  "cash_score_risk_add": {
    "value": 0.1,
    "desc": "新闻风险贡献对现金门槛的上调系数（风险越大，越偏向空仓）。"
  },
  "cash_score_ease_sub": {
    "value": 0.08,
    "desc": "新闻利好贡献对现金门槛的下调系数（利好越多，越偏向开仓）。"
  },
  "cash_adj_uptrend": {
    "value": -0.03,
    "desc": "市场处于上升趋势时，对现金门槛的额外调整（负值=更激进）。"
  },
  "cash_adj_downtrend": {
    "value": 0.05,
    "desc": "市场处于下跌趋势时，对现金门槛的额外调整（正值=更保守）。"
  },
  "cash_adj_highvol": {
    "value": 0.05,
    "desc": "市场处于高波动时，对现金门槛的额外调整。"
  },
  "cash_adj_hotspot": {
    "value": -0.02,
    "desc": "热点状态机触发时，对现金门槛的额外调整（负值=更激进）。"
  },
  "market_regime_switch_days": {
    "value": 3,
    "desc": "市场 Regime 切换确认天数（越大越稳，越小越灵敏）。"
  },
  "industry_regime_switch_days": {
    "value": 3,
    "desc": "行业 Regime 切换确认天数（越大越稳，越小越灵敏）。"
  },
  "hotspot_switch_days": {
    "value": 2,
    "desc": "热点状态机切换确认天数。"
  },
  "hotspot_threshold": {
    "value": 0.5,
    "desc": "热点判定阈值（hotspot_score>=threshold 才算热点）。"
  },
  "hotspot_min_reasons": {
    "value": 2,
    "desc": "热点判定至少需要满足的理由数量（如 flow_surge / catalyst_count 等）。"
  },
  "llm_timeout_sec": {
    "value": 45.0,
    "desc": "LLM 单次请求超时（秒）。弱网可调大。"
  },
  "llm_retries": {
    "value": 3,
    "desc": "LLM 应用层重试次数（指数退避）。弱网可提高，注意会增加耗时。"
  },
  "llm_batch_size": {
    "value": 20,
    "desc": "LLM 批处理大小（每次请求包含多少条新闻）。过大易超时，过小易成本上升。"
  },
  "llm_max_workers": {
    "value": 5,
    "desc": "LLM 并发线程上限。过大易触发超时/限流。"
  },
  "mf_boost_max": {
    "value": 0.02,
    "desc": "主力资金净流入的最大加分（加到 p3/p5）。"
  },
  "mf_boost_scale_wan": {
    "value": 5000.0,
    "desc": "主力资金净流入加分的尺度参数（单位：万）。x/scale 越大，加分越接近 mf_boost_max。"
  },
  "limit_boost": {
    "value": 0.05,
    "desc": "昨日涨停状态的加分（加到 p3/p5；plimit 会额外放大）。"
  },
  "inst_boost_max": {
    "value": 0.08,
    "desc": "龙虎榜机构净买入（过去3天）的最大加分。"
  },
  "inst_boost_scale_wan": {
    "value": 5000.0,
    "desc": "机构净买入加分尺度参数（单位：万）。"
  },
  "inst_penalty_max": {
    "value": 0.1,
    "desc": "机构净卖出（过去3天）的最大惩罚幅度（负分）。"
  },
  "inst_penalty_scale_wan": {
    "value": 3000.0,
    "desc": "机构净卖出惩罚尺度参数（单位：万）。"
  },
  "inst_hard_filter_wan": {
    "value": -5000,
    "desc": "机构过去3天净卖出低于该阈值（单位：万）时，直接将 p3/p5/plimit 置 0（硬过滤）。"
  },
  "industry_news_boost_max": {
    "value": 0.03,
    "desc": "行业新闻加分的最大幅度（加到行业 score）。"
  },
  "industry_news_boost_scale": {
    "value": 6.0,
    "desc": "行业新闻加分的 tanh 尺度参数（越小越敏感）。"
  },
  "policy_cycle_boost_max": {
    "value": 0.02,
    "desc": "政策周期加分的最大幅度（加到行业 score）。"
  },
  "policy_cycle_boost_scale": {
    "value": 6.0,
    "desc": "政策周期加分的 tanh 尺度参数（越小越敏感）。"
  }
}

